    private void ProcessNode(MapNode node)
    {
        if (currentRun == null) return;
        
        selectedNode = node;
        currentRun.Map.CurrentNodeId = node.Id;
        
        currentScreen = node.Type switch
        {
            "COMBAT" or "ELITE" or "BOSS" => "combat",
            "EVENT" => "event",
            "SHOP" or "MARKET" or "BLACK_MARKET" => "shop",
            "REST" or "CAMP" => "rest",
            "TREASURE" or "NPC" or "TRADER" or "BLESSING" => "event",
            _ => "map"
        };
    }
    
    private void OnCombatEnd(bool victory)
    {
        if (currentRun == null || selectedNode == null) return;
        
        if (victory)
        {
            runManager.CompleteNode(currentRun, selectedNode);
            currentScreen = "map";
        }
        else
        {
            currentScreen = "gameover";
        }
    }
    
    private void OnEventEnd()
    {
        if (currentRun == null || selectedNode == null) return;
        runManager.CompleteNode(currentRun, selectedNode);
        currentScreen = "map";
    }
    
    private void OnShopEnd()
    {
        if (currentRun == null || selectedNode == null) return;
        runManager.CompleteNode(currentRun, selectedNode);
        currentScreen = "map";
    }
    
    private void OnRestEnd()
    {
        if (currentRun == null || selectedNode == null) return;
        runManager.CompleteNode(currentRun, selectedNode);
        currentScreen = "map";
    }
    
    private void ViewDeck()
